css.cardContainer:
/* Card Container - Adaptive padding based on scroll state */
.card-container {
  flex: 1;
  display: flex;
  overflow: hidden;
  transition: padding 0.2s ease;
}

.card-container:has([data-scroll-state="no-scroll"]) {
  padding: 20px 20px 20px 0;
}

.card-container:has([data-scroll-state="at-top"]) {
  padding: 20px 20px 0 0;
}

.card-container:has([data-scroll-state="middle"]) {
  padding: 0 20px 0 0;
}

.card-container:has([data-scroll-state="at-bottom"]) {
  padding: 0 20px 20px 0;
}

css.desktopCardContainer:
/* Desktop Card Container - Adaptive chrome based on scroll state */
.desktop-card-container {
  background-color: white;
  height: 100%;
  overflow: auto;
  flex: 1;
  transition: border-radius 0.2s ease, border-color 0.2s ease;
}

.desktop-card-container[data-scroll-state="no-scroll"] {
  border: 1px solid #E9E9E9;
  border-radius: 24px;
}

.desktop-card-container[data-scroll-state="at-top"] {
  border: 1px solid #E9E9E9;
  border-bottom: none;
  border-radius: 24px 24px 0 0;
}

.desktop-card-container[data-scroll-state="middle"] {
  border: 1px solid #E9E9E9;
  border-top: none;
  border-bottom: none;
  border-radius: 0;
}

.desktop-card-container[data-scroll-state="at-bottom"] {
  border: 1px solid #E9E9E9;
  border-top: none;
  border-radius: 0 0 24px 24px;
}

css.pageHeader:
/* Page Header - Sticky with scroll shadow */
.page-header {
  position: relative;
  background-color: white;
  border-bottom: none;
  transition: padding 0.2s ease, box-shadow 0.2s ease, border-bottom 0.15s ease;
}

@media (min-width: 624px) {
  .desktop-card-container .page-header {
    position: sticky;
    top: 0;
    z-index: 100;
    background-color: white;
  }

  .desktop-card-container .page-header--expanded {
    padding: 24px 32px 16px 32px;
    border-bottom: none;
  }

  .desktop-card-container .page-header--collapsed {
    padding: 12px 32px;
    border-bottom: 1px solid var(--goa-color-greyscale-200);
  }
}

/* Scroll shadow below header */
.page-header::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 8px;
  transform: translateY(100%);
  background: linear-gradient(to bottom, rgba(0, 0, 0, 0.08), transparent);
  pointer-events: none;
  opacity: 0;
  visibility: hidden;
  transition: opacity 0.15s ease, visibility 0.15s ease;
}

.page-header--middle::after,
.page-header--atbottom::after {
  opacity: 1;
  visibility: visible;
}

