// App.tsx - Main application shell
import { Routes, Route, Navigate } from 'react-router-dom';
import { MenuProvider } from './contexts/MenuContext';
import { NotificationProvider } from './contexts/NotificationContext';
import { AppLayout } from './components/AppLayout';
import { DashboardPage } from './routes/DashboardPage';
import { MyCasesPage } from './routes/MyCasesPage';
import { AllCasesPage } from './routes/AllCasesPage';
import { CaseDetailPage } from './routes/CaseDetailPage';
import { SearchPage } from './routes/SearchPage';
import { NotificationsPage } from './routes/NotificationsPage';
import { SettingsPage } from './routes/SettingsPage';
import './App.css';

export default function App() {
  return (
    <MenuProvider>
      <NotificationProvider>
        <AppLayout>
          <Routes>
            <Route path="/" element={<DashboardPage />} />
            <Route path="/my-cases" element={<MyCasesPage />} />
            <Route path="/cases" element={<AllCasesPage />} />
            <Route path="/cases/:caseId" element={<CaseDetailPage />} />
            <Route path="/search" element={<SearchPage />} />
            <Route path="/notifications" element={<NotificationsPage />} />
            <Route path="/settings" element={<SettingsPage />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </AppLayout>
      </NotificationProvider>
    </MenuProvider>
  );
}

// AppLayout.tsx - Layout with side menu, scroll state, and content area
import { ReactNode } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  GoabxWorkSideMenu,
  GoabxWorkSideMenuItem
} from '@abgov/react-components/experimental';
import { useMenu } from '../contexts/MenuContext';
import { useNotifications } from '../contexts/NotificationContext';
import { ScrollStateProvider, useScrollState } from '../contexts/ScrollStateContext';
import { PageHeader } from './PageHeader';
import { currentUser } from '../data/mockWorkers';

// Inner component that uses scroll state
function WorkspaceContent({ children }: { children: ReactNode }) {
  const { isMobile } = useMenu();
  const { scrollPosition } = useScrollState();

  if (isMobile) {
    return (
      <div className="mobile-content-container" style={{ backgroundColor: 'white', height: '100%', overflow: 'auto' }}>
        <PageHeader />
        {children}
      </div>
    );
  }

  return (
    <div className="desktop-card-container" data-scroll-state={scrollPosition}>
      <PageHeader />
      {children}
    </div>
  );
}

export function AppLayout({ children }: { children: ReactNode }) {
  const navigate = useNavigate();
  const { isCollapsed, isMobile, toggleMenu } = useMenu();
  const { unreadCount } = useNotifications();

  const handleNavigate = (path: string) => {
    navigate(path);
    if (isMobile) toggleMenu();
  };

  return (
    <ScrollStateProvider>
      <div className="app-layout">
        <GoabxWorkSideMenu
          heading="Case Management"
          url="/"
          userName={currentUser.name}
          userSecondaryText={currentUser.email}
          open={!isCollapsed}
          onToggle={toggleMenu}
          primaryContent={
            <>
              <GoabxWorkSideMenuItem
                icon="home"
                label="Dashboard"
                url="/"
                onClick={() => handleNavigate('/')}
              />
              <GoabxWorkSideMenuItem
                icon="person"
                label="My Cases"
                badge="12"
                url="/my-cases"
                onClick={() => handleNavigate('/my-cases')}
              />
              <GoabxWorkSideMenuItem
                icon="folder"
                label="All Cases"
                url="/cases"
                onClick={() => handleNavigate('/cases')}
              />
              <GoabxWorkSideMenuItem
                icon="search"
                label="Search"
                url="/search"
                onClick={() => handleNavigate('/search')}
              />
            </>
          }
          secondaryContent={
            <>
              <GoabxWorkSideMenuItem
                icon="notifications"
                label="Notifications"
                badge={unreadCount > 0 ? String(unreadCount) : undefined}
                type={unreadCount > 0 ? 'emergency' : undefined}
                url="/notifications"
                onClick={() => handleNavigate('/notifications')}
              />
            </>
          }
          accountContent={
            <>
              <GoabxWorkSideMenuItem
                icon="settings"
                label="Settings"
                url="/settings"
                onClick={() => handleNavigate('/settings')}
              />
              <GoabxWorkSideMenuItem
                icon="log-out"
                label="Logout"
                onClick={() => console.log('Logout')}
              />
            </>
          }
        />

        <main className="card-container">
          <WorkspaceContent>{children}</WorkspaceContent>
        </main>
      </div>
    </ScrollStateProvider>
  );
}

